// Generated by OrchestKit Claude Plugin
// Created: 2026-04-30

/**
 * Delete-Branch Stacked-PR Guard — PreToolUse/Bash hook
 *
 * `gh pr merge ... --delete-branch` (or the GitHub UI equivalent) deletes
 * the head branch after squash-merge. If any other open PR has THAT
 * branch as its `baseRefName`, GitHub silently auto-closes it — and the
 * closed PR cannot be reopened or retargeted via API. Recovery requires
 * rebasing onto main locally and opening a fresh PR.
 *
 * This hook fires on `gh pr merge ... --delete-branch` (and the squash
 * variants), queries `gh pr list --base <head-branch>` for any open
 * dependents, and surfaces them as a warning before the merge runs.
 *
 * Advisory only — does NOT block. Opt out with
 * `ORK_DISABLE_DELETE_BRANCH_GUARD=1`.
 */

import { execSync } from 'node:child_process';
import type { HookInput, HookResult, HookContext } from '../../types.js';
import { outputSilentSuccess, getField } from '../../lib/common.js';
import { NOOP_CTX } from '../../lib/context.js';

const HOOK_NAME = 'pretool/bash/delete-branch-stacked-pr-guard';

// Match `gh pr merge <ref> ... --delete-branch ...` (any merge style)
// `<ref>` is optional (gh defaults to current branch).
const MERGE_DELETE_RE =
  /(^|[&;|\s])gh\s+pr\s+merge(?:\s+\S+)*?\s+(?:[^&;|]*\s)?--delete-branch(?:\s|$)/;

// Match the PR ref (number or URL) on the merge command. `gh pr merge` accepts
// PR number, URL, or branch name as the first positional arg.
const PR_REF_RE = /gh\s+pr\s+merge\s+(\S+)/;

interface PRSummary {
  number: number;
  title: string;
}

/**
 * Resolve the PR being merged → its headRefName (= the branch about to be
 * deleted). If no PR ref on the command line, gh uses the current branch.
 */
function resolveHeadBranch(projectDir: string, command: string): string | null {
  const refMatch = command.match(PR_REF_RE);
  const ref = refMatch?.[1];

  // No-arg merge → current branch is the head
  if (!ref || ref.startsWith('--')) {
    try {
      return execSync('git branch --show-current', {
        cwd: projectDir,
        encoding: 'utf8',
        timeout: 1000,
        stdio: ['pipe', 'pipe', 'ignore'],
      }).trim() || null;
    } catch {
      return null;
    }
  }

  // PR number or URL → ask gh for the headRefName
  try {
    const out = execSync(
      `gh pr view ${ref} --json headRefName -q .headRefName`,
      { cwd: projectDir, encoding: 'utf8', timeout: 5000, stdio: ['pipe', 'pipe', 'ignore'] },
    ).trim();
    return out || null;
  } catch {
    return null;
  }
}

/**
 * Find open PRs whose base is the branch about to be deleted.
 */
function findDependentPRs(projectDir: string, headBranch: string): PRSummary[] {
  try {
    const out = execSync(
      `gh pr list --base ${headBranch} --state open --json number,title --limit 20`,
      { cwd: projectDir, encoding: 'utf8', timeout: 5000, stdio: ['pipe', 'pipe', 'ignore'] },
    ).trim();
    if (!out) return [];
    const parsed = JSON.parse(out);
    return Array.isArray(parsed) ? parsed : [];
  } catch {
    return [];
  }
}

export function deleteBranchStackedPRGuard(
  input: HookInput,
  ctx: HookContext = NOOP_CTX,
): HookResult {
  if (process.env.ORK_DISABLE_DELETE_BRANCH_GUARD === '1') return outputSilentSuccess();
  if (input.tool_name !== 'Bash') return outputSilentSuccess();

  const command = getField<string>(input, 'tool_input.command') || '';
  if (!MERGE_DELETE_RE.test(command)) return outputSilentSuccess();

  const projectDir = ctx.projectDir;
  const headBranch = resolveHeadBranch(projectDir, command);
  if (!headBranch) {
    ctx.log(HOOK_NAME, 'Could not resolve head branch — silent');
    return outputSilentSuccess();
  }

  const dependents = findDependentPRs(projectDir, headBranch);
  if (dependents.length === 0) {
    ctx.log(HOOK_NAME, `No open PRs depend on ${headBranch} — silent`);
    return outputSilentSuccess();
  }

  ctx.log(HOOK_NAME, `Warning: ${dependents.length} stacked PR(s) on ${headBranch}`);

  const list = dependents
    .map(pr => `  - #${pr.number} ${pr.title}`)
    .join('\n');

  return {
    continue: true,
    hookSpecificOutput: {
      additionalContext:
        `[delete-branch-stacked-pr-guard] About to merge with \`--delete-branch\` ` +
        `on \`${headBranch}\`, but ${dependents.length} open PR(s) target it as base:\n` +
        `${list}\n` +
        `Deleting the branch will auto-CLOSE these PRs and they CANNOT be reopened or ` +
        `retargeted via API. Recovery requires \`git rebase origin/main\` + force-push + ` +
        `\`gh pr create\`. Either retarget them first (\`gh pr edit <N> --base main\`) or ` +
        `drop \`--delete-branch\` from this command. ` +
        `(Advisory — merge not blocked. Opt out with ORK_DISABLE_DELETE_BRANCH_GUARD=1.)`,
    },
  };
}

// Testing exports
export { MERGE_DELETE_RE, PR_REF_RE, resolveHeadBranch, findDependentPRs };
